import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.fgRodP1M.js";const p=JSON.parse('{"title":"About","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1777962526000}'),r={name:"about.md"};function i(s,t,l,h,d,c){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><p>I am a <strong>robotics software engineer</strong> focused on reliable field software: <strong>ROS 2</strong>-based architectures, <strong>robot control</strong> and <strong>manipulation</strong>, and <strong>Physical AI</strong> systems where perception, planning, and actuation meet messy reality.</p><h2 id="how-i-work" tabindex="-1">How I work <a class="header-anchor" href="#how-i-work" aria-label="Permalink to &quot;How I work&quot;">​</a></h2><p>I care about systems that stay legible after handoff—clear interfaces, observable behavior, and tests where they buy the most confidence. I enjoy <strong>technical writing</strong> when it sharpens thinking: a good note today saves days of re-discovery later.</p><h2 id="interests" tabindex="-1">Interests <a class="header-anchor" href="#interests" aria-label="Permalink to &quot;Interests&quot;">​</a></h2><ul><li><strong>ROS 2</strong> integration patterns, performance, and operational concerns on real hardware</li><li><strong>Control and manipulation</strong> for contact-rich tasks and human-scale machines</li><li><strong>Physical AI</strong> stacks: data, simulation, evaluation, and honest sim-to-real gaps</li><li><strong>Long-term learning</strong>: revisiting fundamentals, reading primary sources, and keeping a steady writing habit alongside deep implementation work</li></ul><h2 id="what-you-will-not-find-here" tabindex="-1">What you will not find here <a class="header-anchor" href="#what-you-will-not-find-here" aria-label="Permalink to &quot;What you will not find here&quot;">​</a></h2><p>This site is intentionally public. It avoids sensitive <strong>company internal</strong> information, unreleased product specifics, customer-identifying details, and anything that would not be appropriate outside a private lab notebook.</p><h2 id="colophon" tabindex="-1">Colophon <a class="header-anchor" href="#colophon" aria-label="Permalink to &quot;Colophon&quot;">​</a></h2><p>The site is built with <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> and hosted on <a href="https://pages.github.com/" target="_blank" rel="noreferrer">GitHub Pages</a>. If something reads unclear, I treat that as a bug worth fixing in a future edit.</p>',10)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
